var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크 대령은?","JPN":"ジェイク大佐は？","ENG":"How is Colonel Walker?","TWN":"傑克上校現在如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"수술은 잘 끝났습니다. 하지만 의식이 언제 돌아올지는 모릅니다.","JPN":"手術は無事に終わりました。しかし、意識がいつ戻るかはわかりません。","ENG":"The operation went well. But he’s still unconscious.","TWN":"他目前已經做完手術，但還不確定何時會清醒。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아쉽군. 지금은 그 친구의 도움이 절실한 상황인데……","JPN":"惜しいな。今こそ彼の力が切実に必要な状況なのに……","ENG":"That's too bad. We really need his help now.","TWN":"真可惜，現在正是需要他的時候……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 쪽에서는 응답이 없나?","JPN":"コフィンカンパニーからの応答はないのか？","ENG":"Any response from the Coffin Company?","TWN":"科芬公司那邊呢？沒有回應嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"조금 전부터 계속 지원 요청을 하고 있지만…… 그쪽도 뭔가 문제가 발생한 것 같습니다.","JPN":"先ほどから応援要請を続けていますが……\\n向こうも何か問題が発生したようです。","ENG":"We’ve been trying to reach them... but it seems they have their own problems.","TWN":"我有持續向他們請求支援……但不知道是發什麼事，都沒有回應。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……이 모든 일이 한꺼번에 벌어진 것이 우연은 아니겠지.","JPN":"……問題が一気に発生したのは偶然ではなかろう。","ENG":"... I don’t think all this is just a coincidence.","TWN":"……一下子發生這麼多事絕非巧合，"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"누군가 거대한 음모를 통해 상황을 조정하고 있는 게 분명해.","JPN":"誰かが巨大な陰謀を巡らせ、状況をコントロールしているに違いない。","ENG":"There’s someone behind all this, controlling the situation from above.","TWN":"肯定是幕後有人在策畫著什麼巨大的陰謀。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님……","JPN":"中将……","ENG":"Lieutenant General...","TWN":"中將……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"허나 상황이 아무리 불리하더라도 우린 군인이고, 싸워야 한다.","JPN":"しかし、いくら状況が不利であっても、我々は軍人であり、戦わなければならん。","ENG":"But no matter the odds, we have to fight. We’re soldiers, and that’s what we do.","TWN":"不過，我們是軍人，情況再怎麼不利都必須作戰！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 우리는 어떠한 위기에도 대응할 수 있도록 준비해 왔지.","JPN":"そして私たちはいかなる危機にも対応できるように備えてきた。","ENG":"We’ve been training all these years to respond to any circumstance.","TWN":"況且我們一直都有在為各種情況做預備，以防不時之需。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아, 그건 어떻게 됐지?","JPN":"シルビア、アレはどうなっている？","ENG":"Sylvia, how’s it going with the thing?","TWN":"希爾維亞，那個準備得如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……아직 미완성이야. 알고 있잖아.","JPN":"……まだ未完成よ。わかってるでしょ。","ENG":"It’s incomplete. You know that.","TWN":"……還沒完成，你不是也很清楚嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"가동시간은 기껏해야 3분 정도.","JPN":"稼働時間はせいぜい3分程度。","ENG":"It can be activated for three minutes maximum.","TWN":"運作時間頂多3分鐘，"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"예상 출력치를 생각해 보면 그 장비로 대응 가능한 한계선은 기껏해야 5종 정도야.","JPN":"予想出力値を考えると、あの装備で対応可能な限界線はせいぜい第5種程度よ。","ENG":"Based on the calculated output, Category 5 is the most it can deal with.","TWN":"以目前預估的輸出值，它最多只能拿來對付5類。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 정도면 충분하군. 나머지는 실력으로 커버하는 거지.","JPN":"その程度なら十分だ。あとは実力でカバーするのみ。","ENG":"That’ll be enough. I’ll handle the rest with my skills.","TWN":"這樣就夠了，其他就靠實力解決吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마……?","JPN":"おばさん……？","ENG":"Maria?","TWN":"大嬸……？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"예전에는 나도 꽤 적극적인 성격이었단다. 실비아.","JPN":"私も昔はかなり血気盛んだったんだ、シルビア。","ENG":"You know, I used to be an action-packed soldier, Sylvia.","TWN":"以前的我也曾經很積極的，希爾維亞。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"오랜만에 젋은 시절의 기분을 느껴 보도록 할까?","JPN":"久々に若い頃に戻ったつもりで挑もうじゃないか。","ENG":"Now I can feel young again.","TWN":"久違地來回味一下年少輕狂的感覺吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>크워어어─────!!</color>","JPN":"<color=#ff3636>グオオオ─────！！</color>","ENG":"<color=#ff3636>GRRRRRRAAAAH─────!!</color>","TWN":"<color=#ff3636>轟隆隆─────!!</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L30_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL_A","text":{"KOREA":"이런! 큰 공격이 온다! 막을 수 없어!","JPN":"すさまじい攻撃が来るぞ！　止められない！","ENG":"No! It’s a big one! We can’t stop it!","TWN":"可惡！好強烈的攻擊！完全擋不住！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL","text":{"KOREA":"다들 도망쳐!!","JPN":"全員逃げろ！！","ENG":"Everyone, run!","TWN":"大家快逃！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL_A","text":{"KOREA":"뭐야……? 나…… 지금 살아 있는 건가?","JPN":"何だ……？　俺……生きているのか？","ENG":"Huh? I’m... still alive?","TWN":"怎麼回事……？我……還活著嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"모두 괜찮은가. 무사해서 다행이로군.","JPN":"皆、大丈夫か。無事でよかった。","ENG":"Is everyone alright? Good.","TWN":"大家都還好嗎？幸好大家都沒事。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L40_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL_A","text":{"KOREA":"다, 당신 누구야?!","JPN":"あ、あんたは誰だ！？","ENG":"W-who are you?!","TWN":"你…你是誰？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L41_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL","text":{"KOREA":"잠깐! 저 얼굴 예전 자료에서 본 적이 있어!","JPN":"ちょっと待て！　あの顔、昔の資料で見たことがあるぞ！","ENG":"Wait! I know that face! From the old documents!","TWN":"等等！這張臉我好像以前在資料上看過！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL","text":{"KOREA":"분명히 대정화 전쟁 초기 때……. 마, 맙소사…….","JPN":"確か大浄化戦争の初期に……ま、まさか……","ENG":"It was from the early stages of the Grand Purification War...","TWN":"應該是在淨化之戰初期……我的天啊……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL_A","text":{"KOREA":"말도 안 돼! 저 사람이…… 중장님이라고?","JPN":"ありえない！　あの人が……中将？","ENG":"No way! You mean... she’s the Lieutenant General?","TWN":"怎麼可能！她是……中將？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……신진대사 가속 및 생체조직 활성화율 최대치.","JPN":"……新陳代謝加速および生体組織活性化率、最大値。","ENG":"Metabolism acceleration and tissue activation are at the maximum level.","TWN":"……新陳代謝加速和身體組織活化率最大值。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"프로토타입 테크 레벨 5.","JPN":"プロトタイプテックレベル5。","ENG":"Prototype Tech Level 5.","TWN":"原型技術等級5。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"강습형 시공가속기 <color=#ffd34c>가르강튀아</color>. 기동.","JPN":"強襲型時空加速器<color=#ffd34c>ガルガンティア</color>。起動。","ENG":"The assault time-space accelerator, <color=#ffd34c>Garguantia</color>, activated.","TWN":"強襲型時空加速器<color=#ffd34c>加爾剛迪亞</color>啟動！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_ON","text":{"KOREA":"여기는 마리아 안토노프 중장.","JPN":"こちらマリア・アントノフ中将。","ENG":"This is Lieutenant General Maria Antonov.","TWN":"這裡是瑪麗亞·安東諾夫中將。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_ON","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_ON","text":{"KOREA":"지금부터, 전방 제 6종 침식체의 상대는 내가 맡는다!","JPN":"これより、前方第6種侵食体の相手は私が務める！","ENG":"From now on, I will handle the Category 6 C.O. in front!","TWN":"現在起，前方6類侵蝕體就交給我處理！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};